<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='HR'; if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf(); executeSql('INSERT INTO hr_employees(full_name,department,salary,leave_balance) VALUES (?,?,?,?)',[post('full_name'),post('department'),(float)post('salary','0'),(int)post('leave_balance','12')]); header('Location:index.php'); exit;} $rows=fetchAll('SELECT * FROM hr_employees'); include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><form method="post" class="row g-2"><?=csrfField()?><div class="col"><input name="full_name" class="form-control" placeholder="Employee"></div><div class="col"><input name="department" class="form-control" placeholder="Department"></div><div class="col"><input name="salary" type="number" class="form-control" placeholder="Salary"></div><div class="col"><input name="leave_balance" type="number" class="form-control" value="12"></div><div class="col"><button class="btn btn-primary">Add</button></div></form><hr><table class="table"><?php foreach($rows as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['department'])?></td><td><?=$r['salary']?></td><td>Leave: <?=$r['leave_balance']?></td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
